//! Canonical CLI help text.

pub const HELP_TEXT: &str = "slopgate — anti-slop commit gate\n\nUSAGE\n  slopgate <command> [flags]\n\n  Gate commands need --config <path> (path to a slopgate config .toml).\n  init, stats, install-skills, agent-hooks and --help do not.\n\nCOMMANDS\n  --staged --config <path> [--tier fast|commit]   gate staged files\n  scan --scope repo --config <path> [--tier commit] [--format human|json|github]\n                                           immutable full-repository CI gate\n  --file <path> --config <path> [--tier fast|commit]   gate a single file\n  --self-test --config <path>                    run rule-engine self-test\n  stats [--by D] [--since <iso>] [--json] [--config <path>]\n                                           show blocked-incident stats\n  baseline --config <path> [--update|--prune]   manage ratchet baseline\n  audit --config <path> [--since-days N] [--json]   audit baseline drift\n  defect record --config <path> --class <id> --file <path> --line <n> --source <name>\n                                           append reviewer finding\n  harvest --check --config <path>          enforce twice-found rule law\n  init [dir]                               scaffold config\n  install-hooks --config <path>            install pre-commit hook\n  install-skills [--force]                 install bundled agent skills\n  agent-hooks [status|install|reinstall|remove] [--agent <id>]\n                                           manage agent hooks\n  --help, -h                               show help\n\nEXAMPLES\n  slopgate scan --scope repo --tier commit --format github --config .slopgate/config.toml\n  slopgate harvest --check --config .slopgate/config.toml\n  slopgate --staged --config .slopgate/config.toml";
